## Safe Wrappers

### Memory Allocation

```aria
extern "C" {
    fn malloc(size: usize) -> *void;
    fn free(ptr: *void);
}

pub fn safe_alloc(size: usize) -> Result<*void> {
    if size == 0 {
        return Err("Invalid size");
    }

    ptr: *void = extern.malloc(size);
    if ptr == NULL {
        return Err("Allocation failed");
    }

    return Ok(ptr);
}

pub fn safe_free(ptr: *void) {
    if ptr != NULL {
        extern.free(ptr);
    }
}
```

