struct Vec<T> {
    data: []T,
    len: usize,
    capacity: usize
}

impl<T> Vec<T> {
    fn new() -> Vec<T> {
        return Vec{
            data: [],
            len: 0,
            capacity: 0
        };
    }

    fn push(item: T) {
        // Implementation
    }

